/**
 * Tests for LGPD/GDPR User Data Export Engine
 * @see src/lib/compliance/data-export.ts
 */

import {
  buildExportMetadata,
  validateExportRequest,
  buildUserDataExport,
  calculateExportSize,
  formatExportFilename,
  getExportExpiryDate,
  isExportExpired,
  countTotalRecords,
  summarizeExport,
  redactSensitiveFields,
  buildActivityRecord,
  EXPORT_EXPIRY_HOURS,
  EXPORT_COOLDOWN_HOURS,
  DATA_CATEGORIES,
  LGPD_LEGAL_BASIS,
  GDPR_LEGAL_BASIS,
  RETENTION_POLICY,
  type UserProfileData,
  type ProjectData,
  type VideoData,
  type UserSettingsData,
  type ActivityRecord,
  type BillingData,
  type StorageUsageData,
  type UserDataExport,
} from '@/lib/compliance/data-export';

// ─── Fixtures ─────────────────────────────────────────────────────────────────

function createMockProfile(overrides?: Partial<UserProfileData>): UserProfileData {
  return {
    id: 'user-123',
    email: 'joao@example.com',
    name: 'João Silva',
    avatarUrl: null,
    createdAt: '2025-01-01T00:00:00.000Z',
    lastSignIn: '2025-06-01T12:00:00.000Z',
    provider: 'email',
    emailVerified: true,
    ...overrides,
  };
}

function createMockProject(overrides?: Partial<ProjectData>): ProjectData {
  return {
    id: 'proj-1',
    title: 'Meu Projeto',
    description: 'Descrição do projeto',
    status: 'active',
    slideCount: 5,
    duration: 120,
    createdAt: '2025-02-01T00:00:00.000Z',
    updatedAt: '2025-02-15T00:00:00.000Z',
    scenes: [
      {
        id: 'scene-1',
        order: 0,
        duration: 30,
        hasAudio: true,
        hasAvatar: false,
        scriptLength: 200,
      },
    ],
    ...overrides,
  };
}

function createMockVideo(overrides?: Partial<VideoData>): VideoData {
  return {
    id: 'video-1',
    projectId: 'proj-1',
    title: 'Meu Vídeo',
    status: 'completed',
    resolution: '1920x1080',
    duration: 120,
    fileSize: 5242880,
    format: 'mp4',
    createdAt: '2025-03-01T00:00:00.000Z',
    downloadUrl: 'https://storage.example.com/video-1.mp4',
    ...overrides,
  };
}

function createMockSettings(overrides?: Partial<UserSettingsData>): UserSettingsData {
  return {
    theme: 'dark',
    language: 'pt-BR',
    notifications: true,
    defaultVoice: 'edge-tts-pt-br',
    defaultResolution: '1080p',
    onboardingCompleted: true,
    ...overrides,
  };
}

function createMockActivity(overrides?: Partial<ActivityRecord>): ActivityRecord {
  return {
    type: 'login',
    timestamp: '2025-06-01T12:00:00.000Z',
    details: null,
    ...overrides,
  };
}

function createMockBilling(overrides?: Partial<BillingData>): BillingData {
  return {
    plan: 'pro',
    status: 'active',
    currentPeriodStart: '2025-05-01T00:00:00.000Z',
    currentPeriodEnd: '2025-06-01T00:00:00.000Z',
    cancelAtPeriodEnd: false,
    ...overrides,
  };
}

function createMockStorage(overrides?: Partial<StorageUsageData>): StorageUsageData {
  return {
    totalBytes: 10485760,
    totalFiles: 25,
    breakdown: {
      videos: 8388608,
      images: 1048576,
      audio: 524288,
      other: 524288,
    },
    ...overrides,
  };
}

function createFullExportData(): UserDataExport['data'] {
  return {
    profile: createMockProfile(),
    projects: [createMockProject(), createMockProject({ id: 'proj-2', title: 'Projeto 2' })],
    videos: [createMockVideo()],
    settings: createMockSettings(),
    activity: [
      createMockActivity(),
      createMockActivity({ type: 'project_created', details: 'Criou proj-1' }),
    ],
    billing: createMockBilling(),
    storage: createMockStorage(),
  };
}

function createFullExport(overrides?: Partial<UserDataExport>): UserDataExport {
  const data = createFullExportData();
  return {
    exportId: 'export-abc',
    exportDate: '2025-06-15T10:00:00.000Z',
    userId: 'user-123',
    format: 'json',
    version: '1.0',
    data,
    metadata: buildExportMetadata('2025-06-15T09:59:00.000Z', 500, countTotalRecords(data)),
    ...overrides,
  };
}

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('LGPD/GDPR Data Export Engine', () => {
  // ── buildExportMetadata ───────────────────────────────────────────────────

  describe('buildExportMetadata', () => {
    it('should return correct fields', () => {
      const meta = buildExportMetadata('2025-06-15T10:00:00.000Z', 350, 42);

      expect(meta.generatedBy).toBe('system');
      expect(meta.requestedAt).toBe('2025-06-15T10:00:00.000Z');
      expect(meta.processingTimeMs).toBe(350);
      expect(meta.totalRecords).toBe(42);
      expect(meta.generatedAt).toBeDefined();
    });

    it('should include processing time and record count', () => {
      const meta = buildExportMetadata('2025-01-01T00:00:00.000Z', 1200, 100);
      expect(meta.processingTimeMs).toBe(1200);
      expect(meta.totalRecords).toBe(100);
    });

    it('should include all data categories', () => {
      const meta = buildExportMetadata('2025-01-01T00:00:00.000Z', 0, 0);
      expect(meta.dataCategories).toEqual([...DATA_CATEGORIES]);
      expect(meta.dataCategories).toHaveLength(7);
    });

    it('should include legal basis and retention policy', () => {
      const meta = buildExportMetadata('2025-01-01T00:00:00.000Z', 0, 0);
      expect(meta.legalBasis).toContain('LGPD');
      expect(meta.legalBasis).toContain('GDPR');
      expect(meta.retentionPolicy).toBe(RETENTION_POLICY);
    });
  });

  // ── validateExportRequest ─────────────────────────────────────────────────

  describe('validateExportRequest', () => {
    it('should allow first export (no previous)', () => {
      const result = validateExportRequest('user-123', null);
      expect(result.valid).toBe(true);
      expect(result.reason).toBeUndefined();
    });

    it('should block export within cooldown period', () => {
      const recentExport = new Date(Date.now() - 1 * 60 * 60 * 1000).toISOString(); // 1h ago
      const result = validateExportRequest('user-123', recentExport);
      expect(result.valid).toBe(false);
      expect(result.reason).toContain('Aguarde');
    });

    it('should allow export after cooldown expired', () => {
      const oldExport = new Date(Date.now() - 25 * 60 * 60 * 1000).toISOString(); // 25h ago
      const result = validateExportRequest('user-123', oldExport);
      expect(result.valid).toBe(true);
    });

    it('should reject empty userId', () => {
      const result = validateExportRequest('', null);
      expect(result.valid).toBe(false);
      expect(result.reason).toContain('userId');
    });
  });

  // ── buildUserDataExport ───────────────────────────────────────────────────

  describe('buildUserDataExport', () => {
    it('should build correct structure', () => {
      const result = buildUserDataExport({
        userId: 'user-123',
        exportId: 'exp-001',
        profile: createMockProfile(),
        projects: [createMockProject()],
        videos: [createMockVideo()],
        settings: createMockSettings(),
        activity: [createMockActivity()],
        billing: createMockBilling(),
        storage: createMockStorage(),
        requestedAt: '2025-06-15T10:00:00.000Z',
        processingTimeMs: 500,
      });

      expect(result.exportId).toBe('exp-001');
      expect(result.userId).toBe('user-123');
      expect(result.format).toBe('json');
      expect(result.version).toBe('1.0');
    });

    it('should include all data categories', () => {
      const result = buildUserDataExport({
        userId: 'user-123',
        exportId: 'exp-002',
        profile: createMockProfile(),
        projects: [],
        videos: [],
        settings: createMockSettings(),
        activity: [],
        billing: null,
        storage: createMockStorage(),
        requestedAt: '2025-06-15T10:00:00.000Z',
        processingTimeMs: 100,
      });

      expect(result.data.profile).toBeDefined();
      expect(result.data.projects).toBeDefined();
      expect(result.data.videos).toBeDefined();
      expect(result.data.settings).toBeDefined();
      expect(result.data.activity).toBeDefined();
      expect(result.data.storage).toBeDefined();
      expect(result.data.billing).toBeNull();
    });

    it('should set version to 1.0', () => {
      const result = buildUserDataExport({
        userId: 'user-x',
        exportId: 'exp-003',
        profile: createMockProfile(),
        projects: [],
        videos: [],
        settings: createMockSettings(),
        activity: [],
        billing: null,
        storage: createMockStorage(),
        requestedAt: '2025-01-01T00:00:00.000Z',
        processingTimeMs: 0,
      });

      expect(result.version).toBe('1.0');
    });

    it('should compute correct metadata totalRecords', () => {
      const result = buildUserDataExport({
        userId: 'user-123',
        exportId: 'exp-004',
        profile: createMockProfile(),
        projects: [createMockProject(), createMockProject({ id: 'p2' })],
        videos: [createMockVideo()],
        settings: createMockSettings(),
        activity: [createMockActivity(), createMockActivity()],
        billing: createMockBilling(),
        storage: createMockStorage(),
        requestedAt: '2025-06-15T10:00:00.000Z',
        processingTimeMs: 200,
      });

      // 1 (profile) + 2 (projects) + 1 (video) + 1 (settings) + 2 (activity) + 1 (billing) + 1 (storage) = 9
      expect(result.metadata.totalRecords).toBe(9);
    });
  });

  // ── calculateExportSize ───────────────────────────────────────────────────

  describe('calculateExportSize', () => {
    it('should return a positive number', () => {
      const exportData = createFullExport();
      const size = calculateExportSize(exportData);
      expect(size).toBeGreaterThan(0);
    });

    it('should be proportional to data volume', () => {
      const small = createFullExport();
      small.data.projects = [];
      small.data.videos = [];

      const large = createFullExport();
      large.data.projects = Array.from({ length: 50 }, (_, i) =>
        createMockProject({ id: `proj-${i}` }),
      );

      expect(calculateExportSize(large)).toBeGreaterThan(calculateExportSize(small));
    });
  });

  // ── formatExportFilename ──────────────────────────────────────────────────

  describe('formatExportFilename', () => {
    it('should return correct format with userId and date', () => {
      const filename = formatExportFilename('user-123', '2025-06-15T10:00:00.000Z');
      expect(filename).toBe('user-data-export-user-123-2025-06-15.json');
    });

    it('should handle different date strings', () => {
      const filename = formatExportFilename('abc', '2024-01-31T23:59:59.999Z');
      expect(filename).toBe('user-data-export-abc-2024-01-31.json');
    });
  });

  // ── getExportExpiryDate ───────────────────────────────────────────────────

  describe('getExportExpiryDate', () => {
    it('should be 48h after completion', () => {
      const completed = '2025-06-15T10:00:00.000Z';
      const expiry = getExportExpiryDate(completed);
      const expiryDate = new Date(expiry);
      const completedDate = new Date(completed);

      const diffHours =
        (expiryDate.getTime() - completedDate.getTime()) / (1000 * 60 * 60);
      expect(diffHours).toBe(48);
    });
  });

  // ── isExportExpired ───────────────────────────────────────────────────────

  describe('isExportExpired', () => {
    it('should return false for future date', () => {
      const future = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
      expect(isExportExpired(future)).toBe(false);
    });

    it('should return true for past date', () => {
      const past = new Date(Date.now() - 1000).toISOString();
      expect(isExportExpired(past)).toBe(true);
    });

    it('should handle edge case — exactly now', () => {
      // A date at or before now should be expired
      const now = new Date(Date.now() - 1).toISOString();
      expect(isExportExpired(now)).toBe(true);
    });
  });

  // ── countTotalRecords ─────────────────────────────────────────────────────

  describe('countTotalRecords', () => {
    it('should return minimum 3 for empty data (profile + settings + storage)', () => {
      const count = countTotalRecords({
        profile: createMockProfile(),
        projects: [],
        videos: [],
        settings: createMockSettings(),
        activity: [],
        billing: null,
        storage: createMockStorage(),
      });
      expect(count).toBe(3); // profile + settings + storage
    });

    it('should count all categories correctly', () => {
      const count = countTotalRecords(createFullExportData());
      // 1 (profile) + 2 (projects) + 1 (video) + 1 (settings) + 2 (activity) + 1 (billing) + 1 (storage) = 9
      expect(count).toBe(9);
    });

    it('should exclude billing when null', () => {
      const data = createFullExportData();
      data.billing = null;
      const count = countTotalRecords(data);
      // same as above minus 1 for billing
      expect(count).toBe(8);
    });
  });

  // ── summarizeExport ───────────────────────────────────────────────────────

  describe('summarizeExport', () => {
    it('should return correct summary', () => {
      const exportData = createFullExport();
      const summary = summarizeExport(exportData);

      expect(summary.categories).toEqual([...DATA_CATEGORIES]);
      expect(summary.totalRecords).toBe(exportData.metadata.totalRecords);
      expect(summary.estimatedSizeKB).toBeGreaterThan(0);
      expect(summary.projectCount).toBe(exportData.data.projects.length);
      expect(summary.videoCount).toBe(exportData.data.videos.length);
    });

    it('should have 7 categories', () => {
      const summary = summarizeExport(createFullExport());
      expect(summary.categories).toHaveLength(7);
    });
  });

  // ── redactSensitiveFields ─────────────────────────────────────────────────

  describe('redactSensitiveFields', () => {
    it('should redact email partially', () => {
      const profile = createMockProfile({ email: 'joao@example.com' });
      const redacted = redactSensitiveFields(profile);
      expect(redacted.email).not.toBe('joao@example.com');
      expect(redacted.email).toContain('@example.com');
      expect(redacted.email).toContain('*');
    });

    it('should preserve name', () => {
      const profile = createMockProfile({ name: 'Maria' });
      const redacted = redactSensitiveFields(profile);
      expect(redacted.name).toBe('Maria');
    });

    it('should handle single-character local part', () => {
      const profile = createMockProfile({ email: 'a@test.com' });
      const redacted = redactSensitiveFields(profile);
      expect(redacted.email).toContain('@test.com');
    });

    it('should preserve other fields', () => {
      const profile = createMockProfile();
      const redacted = redactSensitiveFields(profile);
      expect(redacted.id).toBe(profile.id);
      expect(redacted.createdAt).toBe(profile.createdAt);
      expect(redacted.provider).toBe(profile.provider);
    });
  });

  // ── buildActivityRecord ───────────────────────────────────────────────────

  describe('buildActivityRecord', () => {
    it('should set correct type and timestamp', () => {
      const before = new Date().toISOString();
      const record = buildActivityRecord('login');
      const after = new Date().toISOString();

      expect(record.type).toBe('login');
      expect(record.timestamp >= before).toBe(true);
      expect(record.timestamp <= after).toBe(true);
    });

    it('should include details when provided', () => {
      const record = buildActivityRecord('project_created', 'Created proj-abc');
      expect(record.details).toBe('Created proj-abc');
    });

    it('should set details to null when not provided', () => {
      const record = buildActivityRecord('video_rendered');
      expect(record.details).toBeNull();
    });
  });

  // ── Constants ─────────────────────────────────────────────────────────────

  describe('Constants', () => {
    it('EXPORT_EXPIRY_HOURS should be 48', () => {
      expect(EXPORT_EXPIRY_HOURS).toBe(48);
    });

    it('EXPORT_COOLDOWN_HOURS should be 24', () => {
      expect(EXPORT_COOLDOWN_HOURS).toBe(24);
    });

    it('DATA_CATEGORIES should have 7 items', () => {
      expect(DATA_CATEGORIES).toHaveLength(7);
    });

    it('LGPD_LEGAL_BASIS should contain "LGPD"', () => {
      expect(LGPD_LEGAL_BASIS).toContain('LGPD');
    });

    it('GDPR_LEGAL_BASIS should contain "GDPR"', () => {
      expect(GDPR_LEGAL_BASIS).toContain('GDPR');
    });

    it('RETENTION_POLICY should mention 48h', () => {
      expect(RETENTION_POLICY).toContain('48h');
    });
  });
});
